types.verbatim:
/**
 * @brief       ICU input active level.
 */
typedef enum {
  ICU_INPUT_ACTIVE_HIGH = 0U,       /**< Trigger on rising edge.            */
  ICU_INPUT_ACTIVE_LOW  = 1U        /**< Trigger on falling edge.           */
} icumode_t;

/**
 * @brief       ICU input channel.
 */
typedef enum {
  ICU_CHANNEL_1 = 0U,               /**< Use TIMxCH1.                      */
  ICU_CHANNEL_2 = 1U                /**< Use TIMxCH2.                      */
} icuchannel_t;

#define ICU_WAITING                        (HAL_DRV_STATE_ERROR + 1U)
#define ICU_ACTIVE                         (HAL_DRV_STATE_ERROR + 2U)

/* Inclusion of LLD header.*/
#include "hal_icu_lld.h"

objinit.implementation:
self->width          = 0U;
self->period         = 0U;
self->enabled_events = 0U;
self->events         = 0U;

#if defined(ICU_DRIVER_EXT_INIT_HOOK)
ICU_DRIVER_EXT_INIT_HOOK(self);
#endif

method.implementation:
osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert(self->state == HAL_DRV_STATE_READY, "not ready");

self->width  = 0U;
self->period = 0U;
self->events = 0U;
self->state  = ICU_WAITING;
icu_lld_start_capture(self);

bool status;

osalDbgCheck(self != NULL);

osalSysLock();
osalDbgAssert((self->state == ICU_WAITING) ||
              (self->state == ICU_ACTIVE),
              "invalid state");
osalDbgAssert(icuAreNotificationsEnabledX(self) == false,
              "notifications enabled");

status = icu_lld_wait_capture(self);
if (status) {
  self->state = ICU_WAITING;
}
else {
  self->width  = icu_lld_get_width(self);
  self->period = icu_lld_get_period(self);
  self->state  = ICU_ACTIVE;
}
osalSysUnlock();

return status;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == ICU_WAITING) ||
              (self->state == ICU_ACTIVE),
              "invalid state");

icu_lld_stop_capture(self);
self->enabled_events = 0U;
self->state = HAL_DRV_STATE_READY;

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == ICU_WAITING) ||
              (self->state == ICU_ACTIVE),
              "invalid state");
osalDbgAssert(drvGetCallbackX(self) != NULL, "undefined callback");

events &= ICU_EVENT_ALL;
self->enabled_events |= events;
icu_lld_enable_events(self, events);

osalDbgCheck(self != NULL);

osalSysLock();
icuEnableEventsI(self, events);
osalSysUnlock();

osalDbgCheckClassI();
osalDbgCheck(self != NULL);
osalDbgAssert((self->state == ICU_WAITING) ||
              (self->state == ICU_ACTIVE),
              "invalid state");

events &= ICU_EVENT_ALL;
self->enabled_events &= ~events;
icu_lld_disable_events(self, events);

osalDbgCheck(self != NULL);

osalSysLock();
icuDisableEventsI(self, events);
osalSysUnlock();

icu_events_t events;
syssts_t sts;

sts = osalSysGetStatusAndLockX();
events = self->events & mask;
self->events &= ~mask;
osalSysRestoreStatusX(sts);

return events;

msg_t msg;

if (config != NULL) {
  self->config = __icu_setcfg_impl(self, config);
  if (self->config == NULL) {
    return HAL_RET_CONFIG_ERROR;
  }
}

msg = icu_lld_start(self);
if (msg != HAL_RET_SUCCESS) {
  self->config = NULL;
  self->width = 0U;
  self->period = 0U;
  self->enabled_events = 0U;
  self->events = 0U;
}

return msg;
